mapper.update:
UPDATE dorm_fee SET amount = #{amount}, basis_area_sqm = #{basisAreaSqm}, basis_days = #{basisDays},
    basis_detail = #{basisDetail}::jsonb, status = #{status}, updated_at = #{updatedAt}
WHERE dorm_fee_id = #{dormFeeId} AND deleted_at IS NULL

mapper.select:
SELECT dorm_fee_id, employee_id, room_id, target_year_month, amount, basis_area_sqm, basis_days,
       basis_detail::text AS basis_detail, status, residence_history_id, created_at, updated_at, deleted_at
FROM dorm_fee WHERE deleted_at IS NULL

    AND employee_id ILIKE CONCAT('%', #{employeeId}, '%')


    AND target_year_month = #{targetYearMonth}


    AND status = #{status}

ORDER BY target_year_month DESC, dorm_fee_id
LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(1) FROM dorm_fee WHERE deleted_at IS NULL

    AND employee_id ILIKE CONCAT('%', #{employeeId}, '%')


    AND target_year_month = #{targetYearMonth}


    AND status = #{status}
